package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.RszConstantOld;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.RszppoKategorie;
import be.schaubroeck.lpb.tools.jpa.gl.RszConstantOldPk;
import be.schaubroeck.lpb.tools.service.RszConstantOldService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedRszConstantOldService implements CachedService, RszConstantOldService {

    @Autowired
    private RszConstantOldService rszConstantOldService;

    private static final ThreadLocal<CachedRszConstantOldBuffer> BUFFER = new ThreadLocal<>();

    public CachedRszConstantOldService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public RszConstantOld getByCategoriePensioenStelselEnDatum(RszppoKategorie categorie, Pensioenstelsel pensioenStelsel, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedRszConstantOldService.getByCategoriePensioenStelselEnDatum");
        CachedRszConstantOldBuffer buffer = CachedRszConstantOldService.getBuffer();
        RszConstantOldKey key = new RszConstantOldKey(categorie, pensioenStelsel, datum);
        RszConstantOld result = buffer.get(key);
        if (result == null) {
            result = rszConstantOldService.getByCategoriePensioenStelselEnDatum(categorie, pensioenStelsel, datum);
            buffer.put(key, result);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public void clearCache() {
        CachedRszConstantOldService.getBuffer().clear();
    }

    private static class CachedRszConstantOldBuffer {

        private final Map<RszConstantOldKey, RszConstantOld> rszConstantOldBuffer = new HashMap<>();

        public RszConstantOld get(RszConstantOldKey key) {
            return rszConstantOldBuffer.get(key);
        }

        public void put(RszConstantOldKey key, RszConstantOld rszConstantOld) {
            rszConstantOldBuffer.put(key, rszConstantOld);
        }

        public void clear() {
            rszConstantOldBuffer.clear();
        }
    }

    private static CachedRszConstantOldBuffer getBuffer() {
        CachedRszConstantOldBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedRszConstantOldBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class RszConstantOldKey {

        private final int categorie;
        private final int pensioenStelsel;
        private final LocalDate datum;

        RszConstantOldKey(RszppoKategorie categorie, Pensioenstelsel pensioenStelsel, LocalDate datum) {
            this.categorie = categorie.getCode();
            this.pensioenStelsel = pensioenStelsel.getCode();
            this.datum = datum;
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<RszConstantOld> findAll() {
        return rszConstantOldService.findAll();
    }

    @Override
    public RszConstantOld create(RszConstantOld constant) {
        return rszConstantOldService.create(constant);
    }

    @Override
    public RszConstantOld update(RszConstantOld constant) {
        return rszConstantOldService.update(constant);
    }

    @Override
    public void delete(RszConstantOld constant) {
        rszConstantOldService.delete(constant);
    }

    @Override
    public RszConstantOld getById(RszConstantOldPk id) {
        return rszConstantOldService.getById(id);
    }

    @Override
    public RszConstantOld getById(RszConstantOldPk id, String fetchFields) {
        return rszConstantOldService.getById(id, fetchFields);
    }


    @Override
    public RszConstantOld getByCriteria(CriteriaBuilder cb) {
        return rszConstantOldService.getByCriteria(cb);
    }


    @Override
    public List<RszConstantOld> findAll(String fetchFields) {
        return rszConstantOldService.findAll(fetchFields);
    }

    @Override
    public List<RszConstantOld> findByCriteria(CriteriaBuilder cb) {
        return rszConstantOldService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return rszConstantOldService.countByCriteria(cb);
    }


}
